const payload = $input.first().json.body ?? $input.first().json;
const plan = payload.plan ?? payload.plan_id ?? 'manual';
const customer = payload.customer ?? {};
const business = payload.business ?? {};
return [{
  json: {
    event: 'ai_employee.purchase_activation_received',
    plan,
    customer_email: customer.email ?? payload.customer_email ?? null,
    business_name: business.name ?? payload.business_name ?? null,
    activation_mode: payload.activation_mode ?? 'manual_review',
    next_steps: [
      'confirm payment and plan',
      'send intake link',
      'create client workspace after multi-client tables exist',
      'create five AI employee drafts from approved intake',
      'map GoHighLevel resources before production activation'
    ],
    safety: {
      no_openai_required: true,
      no_auto_ghl_writes_without_review: true,
      lead_generation_not_in_current_build: true
    },
    received_at: new Date().toISOString()
  }
}];

const item = $input.first().json;
return [{
  json: {
    ...item,
    tasks: [
      { owner: 'OBMC Admin', task: 'Review payment and selected package', status: 'manual' },
      { owner: 'Customer', task: 'Complete business intake', status: 'ready' },
      { owner: 'OBMC Admin', task: 'Create five AI employees', status: 'ready' },
      { owner: 'OBMC Admin', task: 'Run no-LLM workflow tests and adjust handoff rules', status: 'ready' },
      { owner: 'OBMC Admin', task: 'Map GHL resources and approve sync', status: 'manual' }
    ]
  }
}];
